INSERT INTO incidents (id, status_page_id, title, description, status, impact, started_at, resolved_at, created_at, updated_at) VALUES
  (1, 1, 'Elevated latency on Checkout Services', 'We are observing increased response times affecting checkout requests in multiple regions.', 'monitoring', 'major', NOW() - INTERVAL '2 hours 15 minutes', NULL, NOW() - INTERVAL '2 hours 15 minutes', NOW() - INTERVAL '8 minutes'),
  (2, 1, 'Email delivery delays', 'Transactional emails are failing or delayed while our provider experiences connectivity issues.', 'identified', 'major', NOW() - INTERVAL '48 minutes', NULL, NOW() - INTERVAL '48 minutes', NOW() - INTERVAL '6 minutes'),
  (3, 1, 'Intermittent API errors earlier today', 'A subset of API requests returned 5xx responses due to a short-lived deployment issue.', 'resolved', 'minor', NOW() - INTERVAL '9 hours', NOW() - INTERVAL '7 hours 45 minutes', NOW() - INTERVAL '9 hours', NOW() - INTERVAL '7 hours 45 minutes'),
  (4, 2, 'Inbound webhook outage', 'Inbound webhook processing is currently unavailable. Requests may receive 503 responses or time out.', 'investigating', 'critical', NOW() - INTERVAL '36 minutes', NULL, NOW() - INTERVAL '36 minutes', NOW() - INTERVAL '3 minutes'),
  (5, 2, 'Developer Console maintenance', 'Scheduled maintenance is affecting access to the Developer Console while database upgrades are performed.', 'identified', 'maintenance', NOW() - INTERVAL '20 minutes', NULL, NOW() - INTERVAL '20 minutes', NOW() - INTERVAL '5 minutes'),
  (6, 2, 'Outbound webhook delivery lag', 'Outbound deliveries are processing slower than normal due to queue backlog.', 'monitoring', 'minor', NOW() - INTERVAL '3 hours 10 minutes', NULL, NOW() - INTERVAL '3 hours 10 minutes', NOW() - INTERVAL '9 minutes');
