INSERT INTO incident_updates (id, incident_id, status, body, published_at, created_at) VALUES
  (1, 1, 'investigating', 'We are investigating elevated response times on Checkout Services.', NOW() - INTERVAL '2 hours 15 minutes', NOW() - INTERVAL '2 hours 15 minutes'),
  (2, 1, 'identified', 'We identified increased database contention in the checkout path and applied mitigations.', NOW() - INTERVAL '55 minutes', NOW() - INTERVAL '55 minutes'),
  (3, 1, 'monitoring', 'Latency has improved and we are monitoring recovery.', NOW() - INTERVAL '8 minutes', NOW() - INTERVAL '8 minutes'),
  (4, 2, 'investigating', 'We are investigating delays with transactional email delivery.', NOW() - INTERVAL '48 minutes', NOW() - INTERVAL '48 minutes'),
  (5, 2, 'identified', 'Our email provider is experiencing upstream connection failures. Messages are queued for retry.', NOW() - INTERVAL '6 minutes', NOW() - INTERVAL '6 minutes'),
  (6, 3, 'investigating', 'We are investigating intermittent 5xx responses on the Public API.', NOW() - INTERVAL '9 hours', NOW() - INTERVAL '9 hours'),
  (7, 3, 'identified', 'A deployment introduced an invalid cache configuration and has been rolled back.', NOW() - INTERVAL '8 hours 20 minutes', NOW() - INTERVAL '8 hours 20 minutes'),
  (8, 3, 'resolved', 'The rollback completed successfully and API error rates returned to baseline.', NOW() - INTERVAL '7 hours 45 minutes', NOW() - INTERVAL '7 hours 45 minutes'),
  (9, 4, 'investigating', 'We are investigating an outage affecting inbound webhook requests.', NOW() - INTERVAL '36 minutes', NOW() - INTERVAL '36 minutes'),
  (10, 4, 'identified', 'We identified a failed deployment on the webhook receiver fleet and are rolling back.', NOW() - INTERVAL '14 minutes', NOW() - INTERVAL '14 minutes'),
  (11, 4, 'investigating', 'Rollback is in progress. Some requests may still fail during instance replacement.', NOW() - INTERVAL '3 minutes', NOW() - INTERVAL '3 minutes'),
  (12, 5, 'identified', 'Scheduled maintenance has started for the Developer Console database upgrade.', NOW() - INTERVAL '20 minutes', NOW() - INTERVAL '20 minutes'),
  (13, 6, 'identified', 'Outbound webhook deliveries are delayed due to queue buildup.', NOW() - INTERVAL '3 hours 10 minutes', NOW() - INTERVAL '3 hours 10 minutes'),
  (14, 6, 'monitoring', 'Queue depth is decreasing and delivery latency is improving.', NOW() - INTERVAL '9 minutes', NOW() - INTERVAL '9 minutes');
